import{c as e,Q as n,j as o,m as a}from"./chunks/framework.BPKcPtvA.js";const i="/screenshots/sign-in-screen-light.png",r="/screenshots/sign-in-screen-dark.png",m=JSON.parse('{"title":"Signing In","description":"","frontmatter":{},"headers":[],"relativePath":"guide/account/signing-in.md","filePath":"guide/account/signing-in.md","lastUpdated":1779094756000}'),s={name:"guide/account/signing-in.md"};function d(l,t,h,c,g,u){return n(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="signing-in" tabindex="-1">Signing In <a class="header-anchor" href="#signing-in" aria-label="Permalink to &quot;Signing In&quot;">​</a></h1><p>Sign-in to the Exto Console always starts at the same screen: an email field with a <strong>Continue</strong> button.</p><p><img src="'+i+'" alt="Sign-in screen" class="light-only"><img src="'+r+'" alt="Sign-in screen" class="dark-only"></p><h2 id="the-standard-flow" tabindex="-1">The standard flow <a class="header-anchor" href="#the-standard-flow" aria-label="Permalink to &quot;The standard flow&quot;">​</a></h2><ol><li>Open the Console URL.</li><li>Enter your email address. Click <strong>Continue</strong>.</li><li>The Console looks up your organisation and shows the sign-in methods available to you. Possible methods include: <ul><li><strong>Password</strong> — username and password held in Zitadel.</li><li><strong>SSO provider</strong> — Google, Microsoft Azure AD, or any custom OIDC provider your organisation has configured.</li></ul></li><li>If only one method is available, the picker is skipped and you go straight there.</li><li>Authenticate. You are redirected back to the Console and dropped at your home page.</li></ol><p>If you mistyped your email, click the pencil icon next to it to go back and re-enter.</p><h2 id="where-you-land-after-signing-in" tabindex="-1">Where you land after signing in <a class="header-anchor" href="#where-you-land-after-signing-in" aria-label="Permalink to &quot;Where you land after signing in&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Who you are</th><th>Where you land</th></tr></thead><tbody><tr><td>Internal operator (Platform Admin, Infra Ops, Account Manager, QA Admin)</td><td>The platform Dashboard at <code>/dashboard</code>.</td></tr><tr><td>Customer owner or admin</td><td>Their customer&#39;s portal Dashboard at <code>/customers/:customerId/dashboard</code>.</td></tr><tr><td>Customer member with no elevated portal access</td><td>Their personal Account page at <code>/customers/:customerId/account</code>.</td></tr><tr><td>New user, profile not yet completed</td><td>The Complete Profile page. After completing, you continue to your normal home.</td></tr></tbody></table><p>If you belong to multiple customers, the portal includes a customer switcher in the header so you can jump between them without signing out.</p><h2 id="signing-in-from-a-partner-application" tabindex="-1">Signing in from a partner application <a class="header-anchor" href="#signing-in-from-a-partner-application" aria-label="Permalink to &quot;Signing in from a partner application&quot;">​</a></h2><p>When a partner application redirects you to the Console for authentication, the experience is the same — email, method picker, authenticate — but on success you are redirected back to the partner application rather than to the Console.</p><p>If the partner application has not been authorised, you will see the message <strong>&quot;Invalid application. The redirect is not allowed for this client.&quot;</strong> Contact your administrator; they need to register the partner application with the Console.</p><h2 id="common-errors" tabindex="-1">Common errors <a class="header-anchor" href="#common-errors" aria-label="Permalink to &quot;Common errors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Message</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Unable to sign in with this email</strong></td><td>The email is not registered with the Console, or the organisation does not allow your account type to use this sign-in path. Check the email or ask an admin to invite you.</td></tr><tr><td><strong>Too many attempts. Please wait a moment and try again</strong></td><td>Rate limiting kicked in. Wait a minute and retry.</td></tr><tr><td><strong>Invalid application</strong></td><td>A partner application has an invalid registration. Contact support.</td></tr><tr><td><strong>Session expired</strong></td><td>Your previous session is no longer valid. Sign in again from the email field.</td></tr></tbody></table><h2 id="signing-out" tabindex="-1">Signing out <a class="header-anchor" href="#signing-out" aria-label="Permalink to &quot;Signing out&quot;">​</a></h2><p>Open your Account menu in the top right and choose <strong>Sign out</strong>. You will be returned to the email field.</p>',16)])])}const f=e(s,[["render",d]]);export{m as __pageData,f as default};
